// Валидация входящих данных — работает и для Webhook, и для Execute Workflow
// Webhook присылает payload в $json.body, Execute Workflow — в $json напрямую
const raw = $input.first().json;
const input = raw.body || raw;

// Унификация chatId
let chatId = input.chatId || input.chat_id || input.chatID;
if (chatId !== undefined && chatId !== null) {
  chatId = String(chatId).trim();
}

if (!chatId) {
  const keys = Object.keys(input);
  const sample = keys.length
    ? keys.map(k => `${k}=${JSON.stringify(input[k]).slice(0,30)}`).join(', ')
    : '(пустой объект)';
  throw new Error('InputValidator: chatId отсутствует/пуст. Получено: ' + sample);
}

const type = String(input.type || '').toLowerCase().trim();
const validTypes = ['photo', 'document', 'voice', 'text'];
if (!validTypes.includes(type)) {
  return [{ json: {
    chatId, isError: true, _route: 3,
    confirmationText: '\u26A0\uFE0F Неподдерживаемый формат. Отправьте PDF, фото, голосовое или текст.'
  }}];
}

const fileId = String(input.file_id || '').trim();
const textVal = String(input.text || '').trim();

if ((type === 'photo' || type === 'document' || type === 'voice') && !fileId) {
  return [{ json: {
    chatId, isError: true, _route: 3,
    confirmationText: '\u26A0\uFE0F Ошибка: файл не получен.'
  }}];
}

if (type === 'text' && !textVal) {
  return [{ json: {
    chatId, isError: true, _route: 3,
    confirmationText: '\u26A0\uFE0F Пустое сообщение. Напишите текст о платеже.'
  }}];
}

let route = 2;
if (type === 'photo' || type === 'document') route = 0;
else if (type === 'voice') route = 1;

return [{ json: {
  chatId, type,
  file_id: fileId,
  mime_type: String(input.mime_type || input.mimeType || '').trim(),
  text: textVal,
  file_size: Number(input.file_size || 0),
  isError: false,
  _route: route
}}];

// Проверка MIME-типа перед отправкой в Gemini Vision
const d = $input.first().json;
const mime = String(d.mime_type || '').toLowerCase();

const allowed = [
  'application/pdf',
  'image/jpeg',
  'image/jpg',
  'image/png'
];

// Telegram photo часто не даёт mime_type — считаем jpeg по умолчанию
const isPhoto = d.type === 'photo';
const effectiveMime = mime || (isPhoto ? 'image/jpeg' : '');

if (!allowed.includes(effectiveMime)) {
  return [{ json: {
    chatId: d.chatId,
    isError: true,
    confirmationText: '\u26A0\uFE0F Неподдерживаемый формат файла: ' + (mime || '?') + '\nПоддерживаются: PDF, JPG, PNG.',
    _skipApi: true
  }}];
}

// Проверка размера (Telegram лимит 20МБ)
if (d.file_size && d.file_size > 20 * 1024 * 1024) {
  return [{ json: {
    chatId: d.chatId,
    isError: true,
    confirmationText: '\u26A0\uFE0F Файл слишком большой (макс 20 МБ).',
    _skipApi: true
  }}];
}

return [{ json: { ...d, mime_type: effectiveMime, _skipApi: false } }];

// Routes: 0=error (skip API), 1=ok (proceed to TG Get File)
const d = $input.first().json;
return [{ json: { ...d, _mimeRoute: d._skipApi ? 0 : 1 } }];

// ============================================================
// WF-02 Parse Doc — v2.4 (добавлен invoice_number)
// Изменения: извлекается поле invoice_number из ответа Gemini Vision
// ============================================================

function extractGeminiText(item) {
  if (!item) return '';
  if (item.content && item.content.parts && item.content.parts[0] && item.content.parts[0].text) {
    return item.content.parts[0].text;
  }
  if (typeof item.text === 'string' && item.text.length) return item.text;
  if (typeof item.content === 'string' && item.content.length) return item.content;
  if (Array.isArray(item.content) && item.content[0]) {
    const c0 = item.content[0];
    if (typeof c0 === 'string') return c0;
    if (c0.text) return c0.text;
  }
  if (typeof item.response === 'string') return item.response;
  if (item.message && typeof item.message.content === 'string') return item.message.content;
  if (typeof item.output === 'string') return item.output;
  if (typeof item.generatedText === 'string') return item.generatedText;
  if (item.candidates && item.candidates[0] && item.candidates[0].content) {
    const parts = item.candidates[0].content.parts;
    if (parts && parts[0] && parts[0].text) return parts[0].text;
  }
  return '';
}

function normalizeCountry(raw) {
  const s = String(raw || '').toLowerCase().trim();
  if (!s) return 'Беларусь';
  if (s.includes('польш') || s.includes('polsk') || s.includes('poland') ||
      s === 'pl' || s === 'pol') return 'Польша';
  if (s.includes('белар') || s.includes('беларус') || s.includes('belarus') ||
      s.includes('bialo') || s === 'by' || s === 'bel') return 'Беларусь';
  return 'Беларусь';
}

const item = $input.first().json;
const chatId = $('Input Validator').first().json.chatId;

const raw = extractGeminiText(item);

if (!raw) {
  return [{ json: {
    chatId, isError: true,
    confirmationText: '\u26A0\uFE0F Не удалось получить ответ от Gemini. Попробуйте снова.',
    _rawDebug: JSON.stringify(Object.keys(item)).slice(0, 200)
  }}];
}

let parsed;
try {
  const cleaned = raw.replace(/```json\s*/gi, '').replace(/```\s*/g, '');
  const m = cleaned.match(/\{[\s\S]*\}/);
  if (!m) throw new Error('No JSON object found');
  parsed = JSON.parse(m[0]);
} catch (e) {
  return [{ json: {
    chatId, isError: true,
    confirmationText: '\u274C Не удалось распознать документ. Отправьте в лучшем качестве.',
    _parseError: e.message
  }}];
}

if (parsed.error === 'НЕЧИТАЕМ') {
  return [{ json: {
    chatId, isError: true,
    confirmationText: '\u274C Файл нечитаем. Пожалуйста, отправьте повторно в лучшем качестве или другом формате.'
  }}];
}

const status = String(parsed.status || '').includes('Поступление') ? 'Поступление' : 'Выбытие';
const payStatus = (parsed.payStatus === 'Оплачено') ? 'Оплачено' : 'Не оплачено';

const amtRaw = String(parsed.amount || '').replace(/[^0-9.,]/g, '').replace(',', '.');
const currency = String(parsed.currency || '').toUpperCase();
const amount = parseFloat(amtRaw) || 0;

const payDate = (payStatus === 'Не оплачено') ? '' : (parsed.payDate || '');

const country = normalizeCountry(parsed.country);
const counterpartyCountry = String(parsed.counterpartyCountry || '').trim();
const countrySignal = (String(parsed.countrySignal || '').toLowerCase() === 'weak') ? 'weak' : 'strong';
const isMixed = parsed.isMixed === true;

// === invoice_number (v2.4) ===
const invoiceNumber = String(parsed.invoice_number || '').trim();

let aiDescription = String(parsed.aiDescription || '').trim();
if (isMixed && !aiDescription.includes('[смешанная сделка')) {
  aiDescription += (aiDescription ? '. ' : '') + '[смешанная сделка BY\u2194PL]';
}
if (countrySignal === 'weak' && !aiDescription.includes('[страна определена эвристически')) {
  aiDescription += (aiDescription ? '. ' : '') + '[страна определена эвристически]';
}

return [{ json: {
  chatId,
  isError: false,
  hasFile: true,
  type: 'document',
  docDate:        parsed.docDate || '',
  invoice_number: invoiceNumber,          // ← НОВОЕ ПОЛЕ v2.4
  counterparty:   parsed.counterparty || '',
  payDate,
  amount,
  currency,
  status,
  payStatus,
  country,
  counterpartyCountry,
  countrySignal,
  isMixed,
  aiDescription,
  driveUrl:       '',
  mime_type:      $('Input Validator').first().json.mime_type
}}];

// Забираем поля из Doc Route и URL от WF-04
const fields = $('Parse Doc').first().json;
const wf04Out = $input.first().json;
const driveUrl = wf04Out.driveUrl || wf04Out.webViewLink || '';
return [{ json: { ...fields, driveUrl, hasFile: true } }];

// Helper: извлекает текст из ответа Gemini (все известные форматы n8n-ноды)
function extractGeminiText(item) {
  if (!item) return '';
  // Формат 1: item.content.parts[0].text (n8n 2.x @langchain/google-gemini — ВАШ СЛУЧАЙ)
  if (item.content && item.content.parts && item.content.parts[0] && item.content.parts[0].text) {
    return item.content.parts[0].text;
  }
  // Формат 2: item.text
  if (typeof item.text === 'string' && item.text.length) return item.text;
  // Формат 3: item.content как строка
  if (typeof item.content === 'string' && item.content.length) return item.content;
  // Формат 4: item.content как массив
  if (Array.isArray(item.content) && item.content[0]) {
    const c0 = item.content[0];
    if (typeof c0 === 'string') return c0;
    if (c0.text) return c0.text;
  }
  // Формат 5: item.response
  if (typeof item.response === 'string') return item.response;
  // Формат 6: item.message.content
  if (item.message && typeof item.message.content === 'string') return item.message.content;
  // Формат 7: item.output
  if (typeof item.output === 'string') return item.output;
  // Формат 8: item.generatedText
  if (typeof item.generatedText === 'string') return item.generatedText;
  // Формат 9: Gemini raw API с candidates
  if (item.candidates && item.candidates[0] && item.candidates[0].content) {
    const parts = item.candidates[0].content.parts;
    if (parts && parts[0] && parts[0].text) return parts[0].text;
  }
  return '';
}

const item = $input.first().json;
const chatId = $('Input Validator').first().json.chatId;
const raw = extractGeminiText(item).trim();

if (!raw) {
  return [{ json: {
    chatId, isError: true, transcribedText: '',
    confirmationText: '\u274C Не удалось распознать голосовое сообщение. Попробуйте сказать ещё раз или напишите текстом.'
  }}];
}

return [{ json: { chatId, isError: false, transcribedText: raw } }];

const d = $input.first().json;
return [{ json: {
  chatId: d.chatId,
  transcribedText: d.text || '',
  isError: false
}}];

// ============================================================
// WF-03 Parse Text — v2.4 (добавлен invoice_number)
// Изменения: извлекается поле invoice_number из ответа Gemini Text
// ============================================================

function extractGeminiText(item) {
  if (!item) return '';
  if (item.content && item.content.parts && item.content.parts[0] && item.content.parts[0].text) {
    return item.content.parts[0].text;
  }
  if (typeof item.text === 'string' && item.text.length) return item.text;
  if (typeof item.content === 'string' && item.content.length) return item.content;
  if (Array.isArray(item.content) && item.content[0]) {
    const c0 = item.content[0];
    if (typeof c0 === 'string') return c0;
    if (c0.text) return c0.text;
  }
  if (typeof item.response === 'string') return item.response;
  if (item.message && typeof item.message.content === 'string') return item.message.content;
  if (typeof item.output === 'string') return item.output;
  if (typeof item.generatedText === 'string') return item.generatedText;
  if (item.candidates && item.candidates[0] && item.candidates[0].content) {
    const parts = item.candidates[0].content.parts;
    if (parts && parts[0] && parts[0].text) return parts[0].text;
  }
  return '';
}

function normalizeCountry(raw) {
  const s = String(raw || '').toLowerCase().trim();
  if (!s) return 'Беларусь';
  if (s.includes('польш') || s.includes('polsk') || s.includes('poland') ||
      s === 'pl' || s === 'pol') return 'Польша';
  if (s.includes('белар') || s.includes('белорус') || s.includes('belarus') ||
      s.includes('bialo') || s === 'by' || s === 'bel') return 'Беларусь';
  return 'Беларусь';
}

const item = $input.first().json;
const chatId = $('Input Validator').first().json.chatId;
const raw = extractGeminiText(item);

if (!raw) {
  return [{ json: {
    chatId, isError: true,
    confirmationText: '\u26A0\uFE0F Не удалось получить ответ от Gemini.'
  }}];
}

let parsed;
try {
  const cleaned = raw.replace(/```json\s*/gi, '').replace(/```\s*/g, '');
  const m = cleaned.match(/\{[\s\S]*\}/);
  if (!m) throw new Error('No JSON object');
  parsed = JSON.parse(m[0]);
} catch (e) {
  return [{ json: {
    chatId, isError: true,
    confirmationText: '\u26A0\uFE0F Не удалось распознать. Переформулируйте: укажите сумму, валюту и суть операции.'
  }}];
}

const status = String(parsed.status || '').includes('Поступление') ? 'Поступление' : 'Выбытие';
// Для текста default = Оплачено (операция описана в прошедшем времени)
const payStatus = (String(parsed.payStatus || '').includes('Не оплачено')) ? 'Не оплачено' : 'Оплачено';

const amtRaw = String(parsed.amount || '').replace(/[^0-9.,]/g, '').replace(',', '.');
const currency = String(parsed.currency || '').toUpperCase();
const amount = parseFloat(amtRaw) || 0;

const payDate = (payStatus === 'Не оплачено') ? '' : (parsed.payDate || parsed.docDate || '');

const country = normalizeCountry(parsed.country);
const counterpartyCountry = String(parsed.counterpartyCountry || '').trim();
const countrySignal = (String(parsed.countrySignal || '').toLowerCase() === 'weak') ? 'weak' : 'strong';
const isMixed = parsed.isMixed === true;

// === invoice_number (v2.4) ===
const invoiceNumber = String(parsed.invoice_number || '').trim();

let aiDescription = String(parsed.aiDescription || '').trim();
if (isMixed && !aiDescription.includes('[смешанная сделка')) {
  aiDescription += (aiDescription ? '. ' : '') + '[смешанная сделка BY\u2194PL]';
}
if (countrySignal === 'weak' && !aiDescription.includes('[страна определена эвристически')) {
  aiDescription += (aiDescription ? '. ' : '') + '[страна определена эвристически]';
}

return [{ json: {
  chatId,
  isError: false,
  hasFile: false,
  type: 'text',
  docDate:        parsed.docDate || '',
  invoice_number: invoiceNumber,          // ← НОВОЕ ПОЛЕ v2.4
  counterparty:   parsed.counterparty || '',
  payDate,
  amount,
  currency,
  status,
  payStatus,
  country,
  counterpartyCountry,
  countrySignal,
  isMixed,
  aiDescription,
  driveUrl:       '',
  mime_type:      ''
}}];

// ============================================================
// WF-02/03 Build Return — v2.3
// Получает данные из WF-05 Build Confirmation (chatId, confirmationText,
// nrId, status, signedAmount, currency, country).
// Если confirmationText пустой — строим fallback по шаблону PRD §1.8.
// ============================================================

const d = $input.first().json;

let ct = d.confirmationText;
if (!ct) {
  const country = d.country || 'Беларусь';
  const flag = (country === 'Польша')
    ? '\uD83C\uDDF5\uD83C\uDDF1'   // 🇵🇱
    : '\uD83C\uDDE7\uD83C\uDDFE';  // 🇧🇾

  // Путь на Drive
  const rootFolder = (country === 'Польша') ? 'Poland' : 'Belarus';
  let monthFolder = '';
  if (d.docDate && /^\d{2}\.\d{2}\.\d{4}$/.test(d.docDate)) {
    const [, mm, yyyy] = d.docDate.match(/^(\d{2})\.(\d{2})\.(\d{4})$/);
    monthFolder = yyyy + '.' + mm;
  }
  const subFolder = (d.status === 'Поступление') ? 'income' : 'outcome';
  const drivePath = monthFolder
    ? `${rootFolder}/${monthFolder}/${subFolder}/`
    : `${rootFolder}/`;
  const drivePart = d.driveUrl ? '\n\uD83D\uDD17 ' + d.driveUrl : '';

  // v2.3: сборка строки суммы из signedAmount (число) + currency (строка)
  const signedAmt = parseFloat(d.signedAmount);
  const cur = String(d.currency || '').toUpperCase();
  let amtDisplay = '\u2014';
  if (!isNaN(signedAmt) && signedAmt !== 0) {
    const sign = signedAmt >= 0 ? '+' : '-';
    const abs  = Math.abs(signedAmt);
    const fmt  = Number.isInteger(abs) ? String(abs) : abs.toFixed(2);
    amtDisplay = `${sign}${fmt}${cur ? ' ' + cur : ''}`;
  }

  ct = '\u2705 Записано\n\n'
    + '\uD83D\uDCCC ' + (d.nrId || '?.????') + ' | ' + (d.status || '') + '\n'
    + flag + ' ' + country + '\n'
    + '\uD83D\uDCC5 ' + (d.docDate || '\u2014') + '\n'
    + '\uD83C\uDFE2 ' + (d.counterparty || '\u2014') + '\n'
    + '\uD83D\uDCB0 ' + amtDisplay + ' | ' + (d.payStatus || '') + '\n'
    + '\uD83D\uDCC1 ' + drivePath
    + drivePart + '\n\n'
    + '\uD83D\uDCAC ' + (d.aiDescription || '');
}

return [{ json: {
  chatId: d.chatId,
  confirmationText: ct,
  isError: false,
  nrId:    d.nrId    || '',
  status:  d.status  || '',
  country: d.country || 'Беларусь'
}}];

// Возврат в WF-01 с ошибкой
const d = $input.first().json;
return [{ json: {
  chatId: d.chatId,
  confirmationText: d.confirmationText || '\u26A0\uFE0F Произошла ошибка. Попробуйте ещё раз.',
  isError: true
}}];

// Force correct MIME on binary before Gemini Vision
// Gemini поддерживает: image/jpeg, image/png, image/webp, image/heic, image/heif, application/pdf

const item = $input.item;
if (!item.binary || !item.binary.data) {
  throw new Error('No binary data found on input item');
}

// 1) Пытаемся взять MIME из Telegram-сообщения (самый надёжный источник)
//    Подставь правильный путь до message.document.mime_type в твоём графе.
//    Обычно это что-то вроде $('Telegram Trigger').item.json.message.document.mime_type
let tgMime = '';
try {
  const msg = $('Telegram Trigger').item.json.message
           || $('Telegram Trigger').item.json.callback_query?.message;
  tgMime = msg?.document?.mime_type
        || msg?.photo?.[0]?.mime_type
        || '';
} catch (e) {
  tgMime = '';
}

// 2) Если Telegram не подсказал — определяем по расширению имени файла
const fileName = item.binary.data.fileName || '';
const ext = fileName.split('.').pop().toLowerCase();
const extMap = {
  'pdf':  'application/pdf',
  'jpg':  'image/jpeg',
  'jpeg': 'image/jpeg',
  'png':  'image/png',
  'webp': 'image/webp',
};

// 3) Определяем финальный MIME
let finalMime = tgMime && tgMime !== 'application/octet-stream'
  ? tgMime
  : (extMap[ext] || '');

// 4) Если всё равно не определили — магические байты (file signature)
if (!finalMime) {
  const buf = Buffer.from(item.binary.data.data, 'base64');
  if (buf[0] === 0x25 && buf[1] === 0x50 && buf[2] === 0x44 && buf[3] === 0x46) {
    finalMime = 'application/pdf';        // %PDF
  } else if (buf[0] === 0xFF && buf[1] === 0xD8) {
    finalMime = 'image/jpeg';             // JPEG SOI
  } else if (buf[0] === 0x89 && buf[1] === 0x50 && buf[2] === 0x4E && buf[3] === 0x47) {
    finalMime = 'image/png';              // \x89PNG
  } else {
    throw new Error(`Cannot determine supported MIME type. File: ${fileName}`);
  }
}

// 5) Принудительно перезаписываем MIME на бинарнике
item.binary.data.mimeType = finalMime;
item.binary.data.fileType = finalMime.split('/')[0];

return item;

// ============================================================
// WF-02 → WF-04 bridge: упаковываем бинарник в base64
// Run mode: Once for Each Item
// 
// ВАЖНО: поправь имя ноды 'Download File' ниже на то, как
// у тебя в WF-02 называется нода, которая скачала бинарник
// с Telegram (обычно HTTP Request с Response=File).
// ============================================================

const DOWNLOAD_NODE_NAME = 'Download File'; // ← поправь под свою ноду

// Достаём исходный бинарник из ноды скачивания
let srcBinary;
try {
  srcBinary = $(DOWNLOAD_NODE_NAME).item.binary;
} catch (e) {
  throw new Error(`Pack File: cannot find binary on node "${DOWNLOAD_NODE_NAME}". Fix the node name in this script.`);
}

if (!srcBinary || !srcBinary.data || !srcBinary.data.data) {
  throw new Error(`Pack File: no binary.data on node "${DOWNLOAD_NODE_NAME}"`);
}

// MIME из binary (уже починен нодой Fix MIME)
const mimeType = srcBinary.data.mimeType || 'application/octet-stream';

// Конвертируем buffer/base64 в base64-строку
let fileBase64;
if (typeof srcBinary.data.data === 'string') {
  // В N8N данные обычно уже хранятся в base64
  fileBase64 = srcBinary.data.data;
} else {
  // На всякий случай — если Buffer
  fileBase64 = Buffer.from(srcBinary.data.data).toString('base64');
}

// Пробрасываем все поля из парсинга + добавляем base64
return {
  json: {
    ...$json,
    fileBase64,
    mimeType
  }
};

// ============================================================
// Universal MIME Fixer for Gemini Vision / Gemini Audio
// Run mode: Once for Each Item
// Поддерживает: JPEG, PNG, WebP, PDF, OGG, MP3, WAV, M4A
// ============================================================

const item = $input.item;
if (!item.binary || !item.binary.data) {
  throw new Error('No binary data found on input item');
}

// 1) Telegram — самый надёжный источник MIME
let tgMime = '';
try {
  const msg = $('Telegram Trigger').item.json.message
           || $('Telegram Trigger').item.json.callback_query?.message;
  tgMime = msg?.document?.mime_type
        || msg?.photo?.[0]?.mime_type
        || msg?.voice?.mime_type
        || msg?.audio?.mime_type
        || '';
} catch (e) {
  tgMime = '';
}

// 2) Фолбэк: по расширению в fileName
const fileName = item.binary.data.fileName || '';
const ext = fileName.split('.').pop().toLowerCase();
const extMap = {
  // Images & docs
  'pdf':  'application/pdf',
  'jpg':  'image/jpeg',
  'jpeg': 'image/jpeg',
  'png':  'image/png',
  'webp': 'image/webp',
  // Audio (Telegram voice = .oga/.ogg Opus)
  'ogg':  'audio/ogg',
  'oga':  'audio/ogg',
  'opus': 'audio/ogg',
  'mp3':  'audio/mpeg',
  'wav':  'audio/wav',
  'm4a':  'audio/mp4',
  'aac':  'audio/aac',
  'flac': 'audio/flac',
};

let finalMime = tgMime && tgMime !== 'application/octet-stream'
  ? tgMime
  : (extMap[ext] || '');

// 3) Magic bytes — последний рубеж
if (!finalMime) {
  const buf = Buffer.from(item.binary.data.data, 'base64');

  if (buf[0] === 0x25 && buf[1] === 0x50 && buf[2] === 0x44 && buf[3] === 0x46) {
    finalMime = 'application/pdf';                    // %PDF
  } else if (buf[0] === 0xFF && buf[1] === 0xD8) {
    finalMime = 'image/jpeg';                         // JPEG SOI
  } else if (buf[0] === 0x89 && buf[1] === 0x50 && buf[2] === 0x4E && buf[3] === 0x47) {
    finalMime = 'image/png';                          // \x89PNG
  } else if (buf[0] === 0x4F && buf[1] === 0x67 && buf[2] === 0x67 && buf[3] === 0x53) {
    finalMime = 'audio/ogg';                          // OggS
  } else if (buf[0] === 0x52 && buf[1] === 0x49 && buf[2] === 0x46 && buf[3] === 0x46) {
    // RIFF контейнер — смотрим следом
    if (buf[8] === 0x57 && buf[9] === 0x41 && buf[10] === 0x56 && buf[11] === 0x45) {
      finalMime = 'audio/wav';                        // WAVE
    } else if (buf[8] === 0x57 && buf[9] === 0x45 && buf[10] === 0x42 && buf[11] === 0x50) {
      finalMime = 'image/webp';                       // WEBP
    }
  } else if (buf[0] === 0x49 && buf[1] === 0x44 && buf[2] === 0x33) {
    finalMime = 'audio/mpeg';                         // MP3 ID3
  } else if (buf[0] === 0xFF && (buf[1] & 0xE0) === 0xE0) {
    finalMime = 'audio/mpeg';                         // MP3 frame sync
  }

  if (!finalMime) {
    throw new Error(`Cannot determine MIME. File: ${fileName}, bytes: ${buf.slice(0, 8).toString('hex')}`);
  }
}

// 4) Валидация поддерживаемых Gemini типов
const geminiSupported = [
  'image/jpeg', 'image/png', 'image/webp', 'image/heic', 'image/heif',
  'application/pdf',
  'audio/wav', 'audio/mpeg', 'audio/aiff', 'audio/aac', 'audio/ogg', 'audio/flac', 'audio/mp4'
];
if (!geminiSupported.includes(finalMime)) {
  throw new Error(`Unsupported MIME for Gemini: ${finalMime}`);
}

// 5) Перезаписываем
item.binary.data.mimeType = finalMime;
item.binary.data.fileType = finalMime.split('/')[0];

return item;
